<#
.SYNOPSIS
    GUI tool to optimize VHD/VHDX files for selected Hyper-V virtual machines.
.DESCRIPTION
    OptimizeVHDsUI provides a Windows Forms interface that:
    - Self-elevates to local Administrator.
    - Lists local Hyper-V virtual machines (eligible VMs are Off and have no checkpoints).
    - Lets you select one or more VMs, or select all at once.
    Delegates all disk work to Optimize-VHDs.ps1 via a live PowerShell instance.
    - Streams every progress record, warning, and result line into an in-window output box.
    - Updates a progress bar and status label in real time.
    - Shows a summary dialog with totals when the run completes.

    Optimize-VHDs.ps1 must be present in the same folder as this script.

    A VM is skipped when:
    - It is not turned off.
    - It has one or more checkpoints.

.NOTES
    FileName:    Optimize-VHDsUI.ps1
    Author:      Mikael Nystrom
    Contact:     deploymentbunny@outlook.com
    Created:     2026-04-28
    Updated:     2026-04-28
    Twitter:     @mikael_nystrom

    Disclaimer:
    This script is provided "AS IS" with no warranties, confers no rights and
    is not supported by the author.
.LINK
    https://www.deploymentbunny.com
.EXAMPLE
    .\OptimizeVHDsUI.ps1
#>

# Get the ID and security principal of the current user account
$Host.UI.RawUI.WindowTitle = $myInvocation.MyCommand.Definition

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing
[System.Windows.Forms.Application]::EnableVisualStyles()

$Script:ToolName   = "Optimize-VHDsUI"
$Script:IsAdmin          = [bool](([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator))
$Script:ScriptPath       = if (-not [string]::IsNullOrWhiteSpace($PSCommandPath)) { $PSCommandPath } else { $MyInvocation.MyCommand.Path }
$Script:TargetComputer   = $env:COMPUTERNAME
$Script:Credential       = $null

if (-not $Script:IsAdmin) {
    Start-Process -FilePath "powershell.exe" -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"$Script:ScriptPath`"" -Verb RunAs -ErrorAction Stop
    return
}

# Logging Setup
$Script:ScriptName    = (Get-Item -Path $Script:ScriptPath).BaseName
$Script:LogDirectory  = Join-Path -Path $env:TEMP -ChildPath $Script:ScriptName
$Script:LogFile       = Join-Path -Path $Script:LogDirectory -ChildPath "$($Script:ScriptName)_$(Get-Date -Format 'yyyy-MM-dd_HH-mm-ss').log"
if (-not (Test-Path -Path $Script:LogDirectory -PathType Container)) {
    [void](New-Item -Path $Script:LogDirectory -ItemType Directory -Force -ErrorAction SilentlyContinue)
}

# Settings File Setup
$Script:SettingsDirectory = Join-Path -Path $env:LOCALAPPDATA -ChildPath "DeploymentBunny"
$Script:SettingsFile      = Join-Path -Path $Script:SettingsDirectory -ChildPath "$($Script:ScriptName).settings.json"

function Write-TSxLog {
    Param(
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    $timestamp = "{0:yyyy-MM-dd HH:mm:ss.fff}" -f (Get-Date)
    $logLine = "[{0}] {1}" -f $timestamp, $Message
    try {
        Add-Content -Path $Script:LogFile -Value $logLine -ErrorAction SilentlyContinue
    }
    catch {
    }
}

function Write-TSxVerbose {
    Param(
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-TSxLog -Message ("VERBOSE: {0}" -f $Message)
    if ($null -ne $CheckBoxVerbose -and $CheckBoxVerbose.Checked) {
        Add-TSxOutputLine -Line $Message
    }
}

Write-TSxLog -Message "Optimize-VHDsUI started"

function Save-UISettings {
    try {
        if (-not (Test-Path -LiteralPath $Script:SettingsDirectory -PathType Container)) {
            [void](New-Item -Path $Script:SettingsDirectory -ItemType Directory -Force -ErrorAction SilentlyContinue)
        }

        $settings = [PSCustomObject]@{
            HostName       = $TextBoxComputerName.Text.Trim()
            VerboseChecked = $CheckBoxVerbose.Checked
        }

        $settings | ConvertTo-Json -Depth 3 | Out-File -LiteralPath $Script:SettingsFile -Encoding UTF8
        Write-TSxLog "Settings saved: $($Script:SettingsFile)"
    }
    catch {
        Write-TSxLog ("Failed to save settings. Error: {0}" -f $_.Exception.Message)
    }
}

function Import-UISettings {
    if (-not (Test-Path -LiteralPath $Script:SettingsFile -PathType Leaf)) {
        return $null
    }

    try {
        $settings = Get-Content -LiteralPath $Script:SettingsFile -Raw | ConvertFrom-Json
        Write-TSxLog "Settings loaded: $($Script:SettingsFile)"
        return $settings
    }
    catch {
        Write-TSxLog ("Failed to load settings. Error: {0}" -f $_.Exception.Message)
        return $null
    }
}

# Embedded logo (same payload as Remove-VMUI2.ps1)
$PictureString = ""
$imageBytes = [Convert]::FromBase64String($PictureString)
$imageStream = New-Object System.IO.MemoryStream(,$imageBytes)
$LogoImage = [System.Drawing.Image]::FromStream($imageStream)

# Load user32.dll and define ShowWindowAsync function
$DLL = '[DllImport("user32.dll")] public static extern bool ShowWindowAsync(IntPtr hWnd, int nCmdShow);'
Add-Type -MemberDefinition $DLL -Name NativeMethods -Namespace Win32
$currentProcessHandle = (Get-Process -Id $PID).MainWindowHandle
if ($currentProcessHandle -ne [IntPtr]::Zero) {
    [void][Win32.NativeMethods]::ShowWindowAsync($currentProcessHandle, 2)
}

$global:LastRunDetails = New-Object System.Collections.Generic.List[string]
$Script:OutputBuffer = New-Object System.Collections.Generic.List[string]
$Script:OptimizeScriptPath = Join-Path $PSScriptRoot "Optimize-VHDs.ps1"
$Script:LastNativeProgressLine = ""

function Show-TSxDialog {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message,

        [Parameter(Mandatory = $true)]
        [string]$Title,

        [System.Windows.Forms.MessageBoxIcon]$Icon = [System.Windows.Forms.MessageBoxIcon]::Information,

        [System.Windows.Forms.Form]$Owner = $null
    )

    $dialog = New-Object System.Windows.Forms.Form
    $dialog.Text = $Title
    $dialog.Size = New-Object System.Drawing.Size(520, 230)
    $dialog.StartPosition = [System.Windows.Forms.FormStartPosition]::Manual
    $dialog.FormBorderStyle = [System.Windows.Forms.FormBorderStyle]::FixedDialog
    $dialog.MaximizeBox = $false
    $dialog.MinimizeBox = $false
    $dialog.ShowInTaskbar = $false
    $dialog.TopMost = $true

    $iconBox = New-Object System.Windows.Forms.PictureBox
    $iconBox.Location = New-Object System.Drawing.Point(18, 22)
    $iconBox.Size = New-Object System.Drawing.Size(32, 32)
    $iconBox.SizeMode = [System.Windows.Forms.PictureBoxSizeMode]::StretchImage
    $iconBox.Image = ([System.Drawing.SystemIcons]::$Icon).ToBitmap()

    $messageLabel = New-Object System.Windows.Forms.Label
    $messageLabel.Location = New-Object System.Drawing.Point(65, 20)
    $messageLabel.Size = New-Object System.Drawing.Size(430, 120)
    $messageLabel.Text = $Message
    $messageLabel.Font = $Font1

    $okButton = New-Object System.Windows.Forms.Button
    $okButton.Text = "OK"
    $okButton.Size = New-Object System.Drawing.Size(90, 32)
    $okButton.Location = New-Object System.Drawing.Point(405, 150)
    $okButton.Font = $Font1
    $okButton.Add_Click({ $dialog.Close() })

    $dialog.AcceptButton = $okButton
    $dialog.Controls.AddRange(@($iconBox, $messageLabel, $okButton))

    if ($Owner) {
        $dialogLocationX = $Owner.Left + [Math]::Max(20, [int](($Owner.Width - $dialog.Width) / 2))
        $dialogLocationY = $Owner.Top + 120
        $dialog.Location = New-Object System.Drawing.Point($dialogLocationX, $dialogLocationY)
    }
    else {
        $workingArea = [System.Windows.Forms.Screen]::PrimaryScreen.WorkingArea
        $dialog.Location = New-Object System.Drawing.Point(
            [int](($workingArea.Width - $dialog.Width) / 2),
            [int](($workingArea.Height - $dialog.Height) / 2) + 80
        )
    }

    [void]$dialog.ShowDialog($Owner)
}

function ConvertTo-SizeGb {
    param(
        [Parameter(Mandatory = $true)]
        [Int64]$Bytes
    )

    [math]::Round(($Bytes / 1GB), 2)
}

function Add-TSxOutputLine {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Line
    )

    $timestampedLine = "[{0}] {1}" -f (Get-Date -Format "HH:mm:ss"), $Line
    [void]$Script:OutputBuffer.Add($timestampedLine)

    while ($Script:OutputBuffer.Count -gt 400) {
        $Script:OutputBuffer.RemoveAt(0)
    }

    $TextBoxOutput.Lines = $Script:OutputBuffer.ToArray()
    $TextBoxOutput.SelectionStart = $TextBoxOutput.TextLength
    $TextBoxOutput.ScrollToCaret()
}

function Invoke-TSxOptimizeOutputRecord {
    param(
        [Parameter(Mandatory = $true)]
        [object]$EventItem,

        [Parameter(Mandatory = $true)]
        [AllowEmptyCollection()]
        [System.Collections.Generic.List[object]]$ResultSink
    )

    if ($EventItem -is [System.Management.Automation.ErrorRecord]) {
        $errorMessage = $EventItem.Exception.Message
        Add-TSxOutputLine -Line ("ERROR: {0}" -f $errorMessage)
        $LabelStatus.Text = "Error from optimize script"
        Write-TSxLog -Message ("Optimize script error: {0}" -f $errorMessage)
        return
    }

    if ($EventItem.PSObject.Properties.Match("Type").Count -gt 0) {
        $type = [string]$EventItem.Type
        $vmName = [string]$EventItem.VMName
        $diskPath = [string]$EventItem.DiskPath
        $message = [string]$EventItem.Message
        $status = [string]$EventItem.Status
        $savedGb = [double]$EventItem.SavedGB
        $percent = [int]$EventItem.Percent

        if ($percent -ge 0 -and $percent -le 100) {
            $ProgressBar.Value = $percent
        }

        switch ($type) {
            "Progress" {
                $statusText = if ([string]::IsNullOrWhiteSpace($vmName)) {
                    $message
                }
                else {
                    "{0}: {1}" -f $vmName, $message
                }

                $LabelStatus.Text = $statusText
                Add-TSxOutputLine -Line $statusText
                Write-TSxLog -Message $statusText
            }
            "Result" {
                $resultLine = "VM={0}; Disk={1}; Status={2}; SavedGB={3}; Message={4}" -f $vmName, $diskPath, $status, ([math]::Round($savedGb, 2)), $message
                [void]$ResultSink.Add([pscustomobject]@{
                    VMName = $vmName
                    DiskPath = $diskPath
                    Status = $status
                    Reason = $status
                    SavedGB = [math]::Round($savedGb, 2)
                    Message = $message
                })

                Add-TSxOutputLine -Line $resultLine
                Write-TSxLog -Message $resultLine
            }
            "Summary" {
                $LabelStatus.Text = $message
                Add-TSxOutputLine -Line $message
                Write-TSxLog -Message $message
            }
            default {
                $fallbackText = [string]$EventItem
                Add-TSxOutputLine -Line $fallbackText
                Write-TSxLog -Message $fallbackText
            }
        }

        return
    }

    $line = [string]$EventItem
    if (-not [string]::IsNullOrWhiteSpace($line)) {
        Add-TSxOutputLine -Line $line
        Write-TSxLog -Message $line
    }
}

function Invoke-TSxNativeProgressRecord {
    param(
        [Parameter(Mandatory = $true)]
        [System.Management.Automation.ProgressRecord]$ProgressRecord
    )

    if ($ProgressRecord.RecordType -eq [System.Management.Automation.ProgressRecordType]::Completed) {
        return
    }

    $parts = New-Object System.Collections.Generic.List[string]
    if (-not [string]::IsNullOrWhiteSpace($ProgressRecord.Activity)) {
        [void]$parts.Add($ProgressRecord.Activity)
    }
    if (-not [string]::IsNullOrWhiteSpace($ProgressRecord.StatusDescription)) {
        [void]$parts.Add($ProgressRecord.StatusDescription)
    }
    if (-not [string]::IsNullOrWhiteSpace($ProgressRecord.CurrentOperation)) {
        [void]$parts.Add($ProgressRecord.CurrentOperation)
    }

    if ($parts.Count -eq 0) {
        return
    }

    $progressLine = ($parts -join " | ")
    if ($ProgressRecord.PercentComplete -ge 0) {
        $progressLine = "{0} ({1}%)" -f $progressLine, $ProgressRecord.PercentComplete
    }

    $LabelStatus.Text = $progressLine

    if ($progressLine -ne $Script:LastNativeProgressLine) {
        $Script:LastNativeProgressLine = $progressLine
        Add-TSxOutputLine -Line $progressLine
        Write-TSxLog -Message $progressLine
    }
}

function Get-TSxVMNames {
    try {
        $eligible = New-Object System.Collections.Generic.List[string]
        $vms = @(Get-VM -ComputerName $Script:TargetComputer -ErrorAction Stop | Sort-Object -Property Name)

        foreach ($vm in $vms) {
            if ($vm.State -ne "Off") {
                continue
            }

            $snapshots = @(Get-VMSnapshot -VMName $vm.Name -ComputerName $Script:TargetComputer -ErrorAction SilentlyContinue)
            if ($snapshots.Count -gt 0) {
                continue
            }

            [void]$eligible.Add($vm.Name)
        }

        [PSCustomObject]@{
            EligibleNames = $eligible
            TotalCount = $vms.Count
        }
    }
    catch {
        Show-TSxDialog -Message "Failed to load VMs. $($_.Exception.Message)" -Title "Optimize-VHDsUI" -Icon Error -Owner $Form
        [PSCustomObject]@{
            EligibleNames = @()
            TotalCount = 0
        }
    }
}

function Update-TSxVMList {
    Write-TSxLog -Message "UI: Listing VMs from '$($Script:TargetComputer)'"
    $ListBoxVMs.Items.Clear()

    $vmData = Get-TSxVMNames
    $vmNames = @($vmData.EligibleNames)
    foreach ($vmName in $vmNames) {
        [void]$ListBoxVMs.Items.Add($vmName)
    }

    $LabelStatus.Text = "Eligible for selection: $($ListBoxVMs.Items.Count) out of $($vmData.TotalCount)"
    Write-TSxLog -Message "UI: Listed VMs. Eligible=$($ListBoxVMs.Items.Count); Total=$($vmData.TotalCount); Host=$($Script:TargetComputer)"
    Write-TSxVerbose -Message ("List details -> Host={0}; Eligible={1}; Total={2}" -f $Script:TargetComputer, $ListBoxVMs.Items.Count, $vmData.TotalCount)
}

function Set-TSxVMSelection {
    for ($i = 0; $i -lt $ListBoxVMs.Items.Count; $i++) {
        $ListBoxVMs.SetSelected($i, $true)
    }
    $LabelStatus.Text = "Selected all VMs: $($ListBoxVMs.SelectedItems.Count)"
    Write-TSxLog -Message "UI: Select All invoked. Selected=$($ListBoxVMs.SelectedItems.Count)"
}

function Optimize-TSxVM {
    param(
        [Parameter(Mandatory = $true)]
        [string]$VMName
    )

    $resultItems = New-Object System.Collections.Generic.List[object]
    Write-TSxLog -Message "Checking VM: $VMName"

    $vm = Get-VM -Name $VMName -ErrorAction SilentlyContinue
    if (-not $vm) {
        Write-TSxLog -Message "VM '$VMName' not found"
        $resultItems.Add([pscustomobject]@{
            VMName = $VMName
            DiskPath = ""
            Status = "Skipped"
            Reason = "VMNotFound"
            SavedGB = 0
            Message = "VM was not found"
        })
        return $resultItems
    }

    if ($vm.State -ne "Off") {
        Write-TSxLog -Message "VM '$VMName' is not turned off - skipping"
        $resultItems.Add([pscustomobject]@{
            VMName = $VMName
            DiskPath = ""
            Status = "Skipped"
            Reason = "VMNotOff"
            SavedGB = 0
            Message = "VM must be turned off"
        })
        return $resultItems
    }

    $snapshots = @(Get-VMSnapshot -VMName $VMName -ErrorAction SilentlyContinue)
    if ($snapshots.Count -gt 0) {
        Write-TSxLog -Message "VM '$VMName' has checkpoints - skipping"
        $resultItems.Add([pscustomobject]@{
            VMName = $VMName
            DiskPath = ""
            Status = "Skipped"
            Reason = "HasCheckpoints"
            SavedGB = 0
            Message = "VM has checkpoint(s)"
        })
        return $resultItems
    }

    $diskPaths = @(Get-VMHardDiskDrive -VMName $VMName -ErrorAction SilentlyContinue |
        Where-Object { -not [string]::IsNullOrWhiteSpace($_.Path) } |
        Select-Object -ExpandProperty Path -Unique)

    if ($diskPaths.Count -eq 0) {
        Write-TSxLog -Message "VM '$VMName' has no disk paths - skipping"
        $resultItems.Add([pscustomobject]@{
            VMName = $VMName
            DiskPath = ""
            Status = "Skipped"
            Reason = "NoDiskPaths"
            SavedGB = 0
            Message = "No attached VHD/VHDX paths found"
        })
        return $resultItems
    }

    Write-TSxLog -Message "VM '$VMName' has $($diskPaths.Count) disk(s) for evaluation"

    foreach ($diskPath in $diskPaths) {
        if (-not (Test-Path -Path $diskPath)) {
            Write-TSxLog -Message "Disk path '$diskPath' for VM '$VMName' does not exist"
            $resultItems.Add([pscustomobject]@{
                VMName = $VMName
                DiskPath = $diskPath
                Status = "Skipped"
                Reason = "DiskPathMissing"
                SavedGB = 0
                Message = "Disk path does not exist"
            })
            continue
        }

        try {
            $before = Get-VHD -Path $diskPath -ErrorAction Stop
            $beforeGb = ConvertTo-SizeGb -Bytes $before.FileSize
            Write-TSxLog -Message "Optimizing disk '$diskPath' for VM '$VMName'. Current size: $beforeGb GB"

            Optimize-VHD -Path $diskPath -Mode Full -ErrorAction Stop

            $after = Get-VHD -Path $diskPath -ErrorAction Stop
            $afterGb = ConvertTo-SizeGb -Bytes $after.FileSize
            $savedGb = [math]::Round(($beforeGb - $afterGb), 2)

            Write-TSxLog -Message "Successfully optimized disk '$diskPath' for VM '$VMName'. Before=$beforeGb GB; After=$afterGb GB; Saved=$savedGb GB"

            $resultItems.Add([pscustomobject]@{
                VMName = $VMName
                DiskPath = $diskPath
                Status = "Success"
                Reason = "Optimized"
                SavedGB = $savedGb
                Message = "BeforeGB=$beforeGb; AfterGB=$afterGb"
            })
        }
        catch {
            Write-TSxLog -Message "Failed to optimize disk '$diskPath' for VM '$VMName'. Error: $($_.Exception.Message)"
            $resultItems.Add([pscustomobject]@{
                VMName = $VMName
                DiskPath = $diskPath
                Status = "Failed"
                Reason = "OptimizeError"
                SavedGB = 0
                Message = $_.Exception.Message
            })
        }
    }

    return $resultItems
}

function Optimize-TSxSelectedVMs {
    $selected = @($ListBoxVMs.SelectedItems | ForEach-Object { $_.ToString() })
    if ($selected.Count -eq 0) {
        Write-TSxLog -Message "UI: Optimize cancelled - no VMs selected"
        Show-TSxDialog -Message "Please select one or more VMs." -Title "Optimize-VHDsUI" -Icon Warning -Owner $Form
        return
    }

    Write-TSxLog -Message "Starting optimization of $($selected.Count) selected VM(s)"
    Write-TSxVerbose -Message ("Selected VMs -> {0}" -f ($selected -join ", "))

    $ButtonOptimize.Enabled = $false
    $ButtonRefresh.Enabled = $false
    $ButtonSelectAll.Enabled = $false

    try {
        if (-not (Test-Path -Path $Script:OptimizeScriptPath)) {
            Show-TSxDialog -Message "Required script was not found: $Script:OptimizeScriptPath" -Title "Optimize-VHDsUI" -Icon Error -Owner $Form
            return
        }

        $LabelStatus.Text = "Optimizing selected VMs..."
        $global:LastRunDetails.Clear()
        $Script:OutputBuffer.Clear()
        $Script:LastNativeProgressLine = ""
        $TextBoxOutput.Clear()
        Add-TSxOutputLine -Line ("Calling script: {0}" -f $Script:OptimizeScriptPath)
        Write-TSxVerbose -Message ("Log file: {0}" -f $Script:LogFile)

        $ProgressBar.Value = 0
        $ProgressBar.Maximum = 100
        $allResults = New-Object System.Collections.Generic.List[object]

        $powerShell = [powershell]::Create()
        $outputCollection = New-Object 'System.Management.Automation.PSDataCollection[psobject]'
        $inputCollection = New-Object 'System.Management.Automation.PSDataCollection[psobject]'
        $inputCollection.Complete()
        $processedOutputCount = 0
        $processedErrorCount = 0
        $processedWarningCount = 0
        $processedProgressCount = 0
        $asyncResult = $null

        try {
            $isRemote = ($Script:TargetComputer -ine $env:COMPUTERNAME) -and ($Script:TargetComputer -ine 'localhost')
            Write-TSxVerbose -Message ("Execution mode: {0}" -f $(if ($isRemote) { "Remote" } else { "Local" }))
            Write-TSxVerbose -Message ("Target computer: {0}" -f $Script:TargetComputer)
            Write-TSxVerbose -Message ("Credential in use: {0}" -f $(if ($null -ne $Script:Credential) { $Script:Credential.UserName } else { "Current user" }))
            if ($isRemote) {
                [void]$powerShell.AddCommand("Invoke-Command")
                [void]$powerShell.AddParameter("ComputerName", $Script:TargetComputer)
                [void]$powerShell.AddParameter("FilePath", $Script:OptimizeScriptPath)
                if ($null -ne $Script:Credential) {
                    [void]$powerShell.AddParameter("Credential", $Script:Credential)
                    [void]$powerShell.AddParameter("Authentication", [System.Management.Automation.Runspaces.AuthenticationMechanism]::Negotiate)
                }
                [void]$powerShell.AddParameter("ArgumentList", @(,$selected, $true))
            } else {
                [void]$powerShell.AddCommand($Script:OptimizeScriptPath)
                [void]$powerShell.AddParameter("VMnames", $selected)
                [void]$powerShell.AddParameter("EmitStructuredOutput", $true)
            }
            $asyncResult = $powerShell.BeginInvoke($inputCollection, $outputCollection)

            while (
                -not $asyncResult.IsCompleted -or
                $processedOutputCount -lt $outputCollection.Count -or
                $processedErrorCount -lt $powerShell.Streams.Error.Count -or
                $processedWarningCount -lt $powerShell.Streams.Warning.Count -or
                $processedProgressCount -lt $powerShell.Streams.Progress.Count
            ) {
                while ($processedOutputCount -lt $outputCollection.Count) {
                    Invoke-TSxOptimizeOutputRecord -EventItem $outputCollection[$processedOutputCount] -ResultSink $allResults
                    $processedOutputCount++
                }

                while ($processedErrorCount -lt $powerShell.Streams.Error.Count) {
                    Invoke-TSxOptimizeOutputRecord -EventItem $powerShell.Streams.Error[$processedErrorCount] -ResultSink $allResults
                    $processedErrorCount++
                }

                while ($processedWarningCount -lt $powerShell.Streams.Warning.Count) {
                    $warningMessage = [string]$powerShell.Streams.Warning[$processedWarningCount]
                    if (-not [string]::IsNullOrWhiteSpace($warningMessage)) {
                        Add-TSxOutputLine -Line ("WARNING: {0}" -f $warningMessage)
                        Write-TSxLog -Message ("WARNING: {0}" -f $warningMessage)
                    }
                    $processedWarningCount++
                }

                while ($processedProgressCount -lt $powerShell.Streams.Progress.Count) {
                    Invoke-TSxNativeProgressRecord -ProgressRecord $powerShell.Streams.Progress[$processedProgressCount]
                    $processedProgressCount++
                }

                [System.Windows.Forms.Application]::DoEvents()

                if (-not $asyncResult.IsCompleted) {
                    [void]$asyncResult.AsyncWaitHandle.WaitOne(150)
                }
            }

            $null = $powerShell.EndInvoke($asyncResult)
        }
        finally {
            if ($null -ne $powerShell) {
                $powerShell.Dispose()
            }
        }

        $successCount = @($allResults | Where-Object { $_.Status -eq "Success" }).Count
        $skippedCount = @($allResults | Where-Object { $_.Status -eq "Skipped" }).Count
        $failedCount = @($allResults | Where-Object { $_.Status -eq "Failed" }).Count
        $totalSavedGb = [math]::Round((@($allResults | Where-Object { $_.Status -eq "Success" } | Measure-Object -Property SavedGB -Sum).Sum), 2)

        foreach ($row in $allResults) {
            $line = "VM=$($row.VMName); Disk=$($row.DiskPath); Status=$($row.Status); Reason=$($row.Reason); SavedGB=$($row.SavedGB); Message=$($row.Message)"
            [void]$global:LastRunDetails.Add($line)
        }

        Write-TSxLog -Message "Optimization completed. VMs=$($selected.Count); DisksOptimized=$successCount; DisksSkipped=$skippedCount; DisksFailed=$failedCount; TotalSavedGB=$totalSavedGb"

        $summary = @(
            "Optimization completed.",
            "",
            "VMs selected: $($selected.Count)",
            "Disks optimized: $successCount",
            "Disks skipped: $skippedCount",
            "Disks failed: $failedCount",
            "Total saved (GB): $totalSavedGb"
        ) -join "`r`n"

        Show-TSxDialog -Message $summary -Title "Optimize-VHDsUI" -Icon Information -Owner $Form

        $LabelStatus.Text = "Done. Optimized: $successCount, Skipped: $skippedCount, Failed: $failedCount"
        $ProgressBar.Value = 100
    }
    finally {
        $ButtonOptimize.Enabled = $true
        $ButtonRefresh.Enabled = $true
        $ButtonSelectAll.Enabled = $true
    }
}

$Font1        = [System.Drawing.Font]::new("Arial", 10, [System.Drawing.FontStyle]::Bold)
$FontHeading1 = [System.Drawing.Font]::new("Arial", 11, [System.Drawing.FontStyle]::Bold)
$FontHeading2 = [System.Drawing.Font]::new("Arial", 14, [System.Drawing.FontStyle]::Bold)
$FontData     = [System.Drawing.Font]::new("Courier New", 10)

$Form = New-Object System.Windows.Forms.Form
$Form.Size = New-Object System.Drawing.Size(1024, 700)
