$ButtonCredentials.Add_Click({
    try {
        $cred = Get-Credential -Message "Enter credentials for remote Hyper-V host access"
        if ($null -ne $cred) {
            $Script:Credential = $cred
            $LabelStatus.Text = "Credentials set for $($cred.UserName)"
            Write-TSxLog -Message "Credentials updated for user '$($cred.UserName)'"
            Write-TSxVerbose -Message ("Credential selected: {0}" -f $cred.UserName)
        }
    }
    catch {
        $LabelStatus.Text = "Error: Failed to capture credentials"
        Write-TSxLog -Message "Failed to capture credentials: $($_.Exception.Message)"
    }
})

$CheckBoxVerbose.Add_CheckedChanged({
    Write-TSxLog -Message ("UI: Verbose mode set to {0}" -f $CheckBoxVerbose.Checked)
    if ($CheckBoxVerbose.Checked) {
        Add-TSxOutputLine -Line ("Log file: {0}" -f $Script:LogFile)
    }
})

$ButtonConnect.Add_Click({
    $computerName = $TextBoxComputerName.Text.Trim()
    if ([string]::IsNullOrWhiteSpace($computerName)) {
        $computerName = $env:COMPUTERNAME
    }
    Write-TSxLog -Message "UI: Connect sequence started for host '$computerName'"
    $LabelStatus.Text = "Connecting to $computerName..."
    [System.Windows.Forms.Application]::DoEvents()
    try {
        if ($null -ne $Script:Credential) {
            Write-TSxVerbose -Message ("Attempting remote connection with credential '{0}'" -f $Script:Credential.UserName)
            Test-WSMan -ComputerName $computerName -Credential $Script:Credential -Authentication Negotiate -ErrorAction Stop | Out-Null
        } else {
            Write-TSxVerbose -Message "Attempting remote connection with current user credentials"
            Test-WSMan -ComputerName $computerName -ErrorAction Stop | Out-Null
        }
        $Script:TargetComputer = $computerName
        $LabelStatus.Text = "Connected to $computerName. Listing VMs..."
        Write-TSxLog -Message "Connected to $computerName"
        Update-TSxVMList
    }
    catch {
        $LabelStatus.Text = "Error: Cannot connect to $computerName"
        Write-TSxLog -Message "Connection failed to ${computerName}: $($_.Exception.Message)"
        Show-TSxDialog -Message "Cannot connect to '$computerName'.`r`n`r`n$($_.Exception.Message)" -Title "Optimize-VHDsUI" -Icon Error -Owner $Form
    }
})
$ButtonRefresh.Add_Click({ Update-TSxVMList })
$ButtonSelectAll.Add_Click({ Set-TSxVMSelection })
$ButtonOptimize.Add_Click({ Optimize-TSxSelectedVMs })
$ButtonElevate.Add_Click({
    Start-Process -FilePath "powershell.exe" -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"$Script:ScriptPath`"" -Verb RunAs -ErrorAction Stop
    $Form.Close()
})
$ButtonClose.Add_Click({ $Form.Close() })
$Form.Add_Load({
    $loadedSettings = Import-UISettings
    if ($loadedSettings) {
        if (-not [string]::IsNullOrWhiteSpace($loadedSettings.HostName)) {
            $TextBoxComputerName.Text = [string]$loadedSettings.HostName
        }
        if ($null -ne $loadedSettings.VerboseChecked) {
            $CheckBoxVerbose.Checked = [bool]$loadedSettings.VerboseChecked
        }
    }
})

$Form.Add_FormClosing({
    Save-UISettings
})

$Form.Add_Shown({ $LabelStatus.Text = "Ready. Click 'List VMs' to load virtual machines." })

[void]$Form.ShowDialog()
